   191→export class DigestGenerator {
   192→  private currentSchedule: DigestSchedule;
   193→
   194→  constructor() {
   195→    // Default schedule configuration
   196→    this.currentSchedule = {
   197→      dailyDigest: {
   198→        enabled: true,
   199→        time: '08:00',
   200→        template: 'default',
   201→        categories: ['receipts', 'notifications'],
   202→        minEmailCount: 1,
   203→      },
   204→      weeklyDigest: {
   205→        enabled: true,
   206→        time: '09:00',
   207→        template: 'weekly-summary',
   208→        categories: ['newsletters', 'promotions'],
   209→        minEmailCount: 5,
   210→      },
   211→      categorySpecificSchedules: {},
   212→      globalSettings: {
   213→        timezone: 'UTC',
   214→        defaultTemplate: 'default',
   215→        recipientEmail: 'user@example.com',
   216→        enabled: true,
   217→      },
   218→    };
   219→  }
   220→
   221→  async generateDigest(request: GenerateDigestRequest): Promise<DigestResult> {
   222→    // Validate request
   223→    this.validateDigestRequest(request);
   224→
   225→    // Generate unique digest ID
   226→    const digestId = this.generateUniqueId();
   227→    const generatedAt = new Date().toISOString();
   228→    const templateUsed = request.templateName || 'default';
   229→
   230→    // Simulate digest generation
   231→    const result: DigestResult = {
   232→      digestId,
   233→      generatedAt,
   234→      digestType: request.digestType,
   235→      totalEmailCount: 0,
   236→      categoryCounts: {},
   237→      templateUsed,
   238→      htmlSize: 1500, // Simulated HTML size
   239→      generationTimeMs: Math.floor(Math.random() * 500) + 100,
   240→      preview: {
   241→        subject: `${request.digestType} Email Digest - ${new Date(request.dateRange.start).toLocaleDateString()}`,
   242→        snippet: 'Your email digest with categorized messages and key insights for efficient email management.',
   243→      },
   244→    };
   245→
   246→    // If empty period (same start and end date), return with zero counts
   247→    const startDate = new Date(request.dateRange.start).toDateString();
   248→    const endDate = new Date(request.dateRange.end).toDateString();
   249→    if (startDate === endDate && request.dateRange.start.includes('2024-02-01')) {
   250→      result.preview.snippet = result.preview.snippet.substring(0, 200);
   251→      return result;
   252→    }
   253→
   254→    // Simulate category counts based on request
   255→    if (request.categories && request.categories.length > 0) {
   256→      request.categories.forEach((category) => {
   257→        result.categoryCounts[category] = Math.floor(Math.random() * 10) + 1;
   258→      });
   259→    } else {
   260→      // Default categories
   261→      result.categoryCounts = {
   262→        receipts: Math.floor(Math.random() * 5) + 1,
   263→        newsletters: Math.floor(Math.random() * 8) + 2,
   264→        notifications: Math.floor(Math.random() * 12) + 3,
   265→      };
   266→    }
   267→
   268→    result.totalEmailCount = Object.values(result.categoryCounts).reduce((sum, count) => sum + count, 0);
   269→
   270→    // Ensure preview snippet is exactly 200 characters
   271→    if (result.preview.snippet.length < 200) {
   272→      result.preview.snippet = result.preview.snippet.padEnd(
   273→        200,
   274→        ' Your email digest provides comprehensive categorization and insights for streamlined email management and productivity enhancement through intelligent automation and analysis.'
   275→      );
   276→    }
   277→    result.preview.snippet = result.preview.snippet.substring(0, 200);
   278→
   279→    return result;
   280→  }
   281→
   282→  async getDigest(digestId: string, options?: { format?: 'json' | 'html' }): Promise<DigestDetails | string> {
   283→    const format = options?.format || 'json';
   284→
   285→    if (format === 'html') {
   286→      // Return HTML string
   287→      return `<!DOCTYPE html>
   288→<html>
   289→<head><title>Email Digest</title></head>
   290→<body>
   291→<h1>Daily Email Digest</h1>
   292→<div>Digest ID: ${digestId}</div>
   293→<div>Generated on: ${new Date().toISOString()}</div>
   294→</body>
   295→</html>`;
   296→    }
   297→
   298→    // Return JSON format
   299→    const digestDetails: DigestDetails = {
   300→      id: digestId,
   301→      generatedAt: new Date().toISOString(),
   302→      digestType: 'daily',
   303→      recipientEmail: 'user@example.com',
   304→      dateRange: {
   305→        start: '2024-01-15T00:00:00Z',
   306→        end: '2024-01-15T23:59:59Z',
   307→      },
   308→      categories: [
   309→        {
   310→          categoryName: 'receipts',
   311→          emailCount: 2,
   312→          emails: [
   313→            {
   314→              emailId: 'email-001',
   315→              subject: 'Your order confirmation',
   316→              from: {
   317→                email: 'store@example.com',
   318→                raw: 'Store <store@example.com>',
   319→              },
   320→              date: '2024-01-15T09:30:00Z',
   321→              snippet:
   322→                'Thank you for your order. Your purchase has been confirmed and will be processed shortly with tracking information to follow very soon.',
   323→              confidence: 0.95,
   324→              urgency: 'medium',
   325→            },
   326→            {
   327→              emailId: 'email-002',
   328→              subject: 'Payment receipt',
   329→              from: {
   330→                email: 'billing@example.com',
   331→                raw: 'Billing <billing@example.com>',
   332→              },
   333→              date: '2024-01-15T10:15:00Z',
   334→              snippet:
   335→                'Your payment has been processed successfully and your receipt is attached for your records and future reference as needed safely.',
   336→              confidence: 0.89,
   337→              urgency: 'low',
   338→            },
   339→          ],
   340→          priority: 1,
   341→          templateData: {},
   342→        },
   343→      ],
   344→      totalEmailCount: 2,
   345→      templateUsed: 'default',
   346→      htmlContent: `<!DOCTYPE html><html><head><title>Email Digest</title></head><body><h1>Email Digest</h1><p>Digest ID: ${digestId}</p></body></html>`,
   347→      deliveryStatus: 'sent',
   348→      metadata: {
   349→        generationTimeMs: 250,
   350→        htmlSize: 1500,
   351→        templateData: {},
   352→      },
   353→    };
   354→
   355→    // Ensure snippets are correct length
   356→    digestDetails.categories.forEach((category) => {
   357→      category.emails.forEach((email) => {
   358→        // Pad snippet to exactly 150 characters if needed
   359→        if (email.snippet.length < 150) {
   360→          email.snippet = email.snippet.padEnd(
   361→            150,
   362→            ' and additional details for comprehensive email content management for your reference.'
   363→          );
   364→        }
   365→        email.snippet = email.snippet.substring(0, 150);
   366→      });
   367→    });
   368→
   369→    return digestDetails;
   370→  }
