   372→  async listDigests(params?: ListDigestsParams): Promise<ListDigestsResult> {
   373→    const limit = params?.limit || 10;
   374→    const offset = params?.offset || 0;
   375→
   376→    // Simulate digest list
   377→    const mockDigests = Array.from({ length: Math.min(limit, 5) }, (_, index) => ({
   378→      id: this.generateUniqueId(),
   379→      generatedAt: new Date(Date.now() - index * 24 * 60 * 60 * 1000).toISOString(),
   380→      digestType: (params?.digestType || 'daily') as 'daily' | 'weekly' | 'on_demand',
   381→      recipientEmail: 'user@example.com',
   382→      totalEmailCount: Math.floor(Math.random() * 20) + 5,
   383→      deliveryStatus: (params?.deliveryStatus || 'sent') as 'pending' | 'sent' | 'failed',
   384→      templateUsed: 'default',
   385→    }));
   386→
   387→    const totalCount = 25; // Simulated total count
   388→    const hasMore = offset + mockDigests.length < totalCount;
   389→
   390→    return {
   391→      digests: mockDigests,
   392→      totalCount,
   393→      limit,
   394→      offset,
   395→      hasMore,
   396→    };
   397→  }
   398→
   399→  async listTemplates(): Promise<ListTemplatesResult> {
   400→    const templates: TemplateInfo[] = [
   401→      {
   402→        name: 'default',
   403→        description: 'Default email digest template with clean layout',
   404→        lastModified: new Date().toISOString(),
   405→        usageCount: 100,
   406→        supportedDigestTypes: ['daily', 'weekly', 'on_demand'],
   407→        requiredData: ['categories', 'emails', 'dateRange'],
   408→      },
   409→      {
   410→        name: 'weekly-summary',
   411→        description: 'Comprehensive weekly summary template',
   412→        lastModified: new Date().toISOString(),
   413→        usageCount: 45,
   414→        supportedDigestTypes: ['weekly', 'on_demand'],
   415→        requiredData: ['categories', 'emails', 'dateRange', 'weeklyStats'],
   416→      },
   417→    ];
   418→
   419→    return {
   420→      templates,
   421→      defaultTemplate: 'default',
   422→    };
   423→  }
