   425→  async previewTemplate(templateName: string, request: PreviewTemplateRequest): Promise<string> {
   426→    // Validate template exists
   427→    const validTemplates = ['default', 'weekly-summary', 'modern-daily'];
   428→    if (!validTemplates.includes(templateName)) {
   429→      throw new Error(`Template not found: ${templateName}`);
   430→    }
   431→
   432→    // Generate preview HTML with sample data
   433→    const sampleData = request.sampleData;
   434→    const html = `<!DOCTYPE html>
   435→<html>
   436→<head>
   437→  <title>Email Digest Preview</title>
   438→  <style>body { font-family: Arial, sans-serif; }</style>
   439→</head>
   440→<body>
   441→  <h1>${sampleData.digestType} Email Digest</h1>
   442→  <p>Generated: ${sampleData.generatedAt}</p>
   443→  <p>Recipient: ${sampleData.recipientEmail}</p>
   444→  <h2>Categories</h2>
   445→  ${sampleData.categories
   446→    .map(
   447→      (category) => `
   448→    <div>
   449→      <h3>${category.categoryName}</h3>
   450→      <p>Emails: ${category.emailCount}</p>
   451→      ${category.emails
   452→        .map(
   453→          (email) => `
   454→        <div style="margin-left: 20px; border: 1px solid #ccc; padding: 10px; margin: 5px;">
   455→          <h4>${email.subject}</h4>
   456→          <p>From: ${email.from.email}</p>
   457→          <p>Date: ${email.date}</p>
   458→          <p>${email.snippet}</p>
   459→        </div>`
   460→        )
   461→        .join('')}
   462→    </div>`
   463→    )
   464→    .join('')}
   465→</body>
   466→</html>`;
   467→
   468→    return html;
   469→  }
