   471→  async getSchedule(): Promise<DigestSchedule> {
   472→    return { ...this.currentSchedule };
   473→  }
   474→
   475→  async updateSchedule(schedule: DigestSchedule): Promise<DigestSchedule> {
   476→    // Validate the schedule configuration
   477→    this.validateSchedule(schedule);
   478→
   479→    // Update the current schedule
   480→    this.currentSchedule = { ...schedule };
   481→
   482→    return { ...this.currentSchedule };
   483→  }
   484→
   485→  async sendDigest(digestId: string, request: SendDigestRequest): Promise<SendDigestResult> {
   486→    const recipientEmail = request.overrideRecipient || this.currentSchedule.globalSettings.recipientEmail;
   487→    const isTestMode = request.testMode || false;
   488→
   489→    // Simulate email delivery
   490→    const result: SendDigestResult = {
   491→      digestId,
   492→      deliveredAt: new Date().toISOString(),
   493→      recipientEmail,
   494→      deliveryStatus: 'sent',
   495→      messageId: isTestMode ? `test-${digestId}` : `msg-${Date.now()}`,
   496→      deliveryTimeMs: Math.floor(Math.random() * 1000) + 100,
   497→      retryCount: 0,
   498→    };
   499→
   500→    return result;
   501→  }
   502→
   503→  private generateUniqueId(): string {
   504→    // Generate a proper UUID v4 format for consistency with tests
   505→    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
   506→      const r = (Math.random() * 16) | 0;
   507→      const v = c === 'x' ? r : (r & 0x3) | 0x8;
   508→      return v.toString(16);
   509→    });
   510→  }
   511→
   512→  private validateDigestRequest(request: GenerateDigestRequest): void {
   513→    // Validate digest type
   514→    if (!['daily', 'weekly', 'on_demand'].includes(request.digestType)) {
   515→      throw new Error(`Validation failed: Invalid digest type: ${request.digestType}`);
   516→    }
   517→
   518→    // Validate email format
   519→    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   520→    if (!emailRegex.test(request.recipientEmail)) {
   521→      throw new Error(`Invalid email format: ${request.recipientEmail}`);
   522→    }
   523→
   524→    // Validate date range
   525→    const startDate = new Date(request.dateRange.start);
   526→    const endDate = new Date(request.dateRange.end);
   527→
   528→    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
   529→      throw new Error('Invalid date format in dateRange');
   530→    }
   531→
   532→    if (startDate > endDate) {
   533→      throw new Error('Date range start must be before end');
   534→    }
   535→  }
   536→
   537→  private validateSchedule(schedule: DigestSchedule): void {
   538→    // Validate time format (HH:MM)
   539→    const timeRegex = /^([01]?[0-9]|2[0-3]):[0-5][0-9]$/;
   540→
   541→    if (!timeRegex.test(schedule.dailyDigest.time)) {
   542→      throw new Error(`Invalid time format for daily digest: ${schedule.dailyDigest.time}`);
   543→    }
   544→
   545→    if (!timeRegex.test(schedule.weeklyDigest.time)) {
   546→      throw new Error(`Invalid time format for weekly digest: ${schedule.weeklyDigest.time}`);
   547→    }
   548→
   549→    // Validate minEmailCount is non-negative
   550→    if (schedule.dailyDigest.minEmailCount < 0) {
   551→      throw new Error('Daily digest minEmailCount must be non-negative');
   552→    }
   553→
   554→    if (schedule.weeklyDigest.minEmailCount < 0) {
   555→      throw new Error('Weekly digest minEmailCount must be non-negative');
   556→    }
   557→
   558→    // Validate email format
   559→    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   560→    if (!emailRegex.test(schedule.globalSettings.recipientEmail)) {
   561→      throw new Error(`Invalid email format: ${schedule.globalSettings.recipientEmail}`);
   562→    }
   563→
   564→    // Validate timezone format (basic IANA format check)
   565→    const timezoneRegex = /^[A-Za-z_]+\/[A-Za-z_]+$/;
   566→    const validTimezones = [
   567→      'UTC',
   568→      'America/New_York',
   569→      'Europe/London',
   570→      'Asia/Tokyo',
   571→      'Australia/Sydney',
   572→      'America/Los_Angeles',
   573→      'Europe/Paris',
   574→    ];
   575→
   576→    if (
   577→      schedule.globalSettings.timezone !== 'UTC' &&
   578→      !timezoneRegex.test(schedule.globalSettings.timezone) &&
   579→      !validTimezones.includes(schedule.globalSettings.timezone)
   580→    ) {
   581→      throw new Error(`Invalid timezone format: ${schedule.globalSettings.timezone}`);
   582→    }
   583→
   584→    // Validate category-specific schedules
   585→    if (schedule.categorySpecificSchedules) {
   586→      const priorities = new Set<number>();
   587→
   588→      for (const [category, categorySchedule] of Object.entries(schedule.categorySpecificSchedules)) {
   589→        // Check priority range
   590→        if (categorySchedule.priority < 1 || categorySchedule.priority > 10) {
   591→          throw new Error(`Category ${category} priority must be between 1 and 10`);
   592→        }
   593→
   594→        // Check for duplicate priorities
   595→        if (priorities.has(categorySchedule.priority)) {
   596→          throw new Error(`Duplicate priority ${categorySchedule.priority} found in category schedules`);
   597→        }
   598→        priorities.add(categorySchedule.priority);
   599→
   600→        // Validate digest type
   601→        if (!['daily', 'weekly'].includes(categorySchedule.digestType)) {
   602→          throw new Error(`Invalid digestType for category ${category}: ${categorySchedule.digestType}`);
   603→        }
   604→      }
   605→    }
   606→
   607→    // Validate template existence (basic check)
   608→    const validTemplates = [
   609→      'default',
   610→      'modern-daily',
   611→      'comprehensive-weekly',
   612→      'urgent-alerts',
   613→      'receipt-summary',
   614→      'receipt-focused',
   615→      'social-digest',
   616→      'weekly-summary',
   617→    ];
   618→
   619→    if (!validTemplates.includes(schedule.dailyDigest.template)) {
   620→      throw new Error(`Template not found: ${schedule.dailyDigest.template}`);
   621→    }
   622→
   623→    if (!validTemplates.includes(schedule.weeklyDigest.template)) {
   624→      throw new Error(`Template not found: ${schedule.weeklyDigest.template}`);
   625→    }
   626→
   627→    if (!validTemplates.includes(schedule.globalSettings.defaultTemplate)) {
   628→      throw new Error(`Default template not found: ${schedule.globalSettings.defaultTemplate}`);
   629→    }
   630→
   631→    // Validate category-specific templates
   632→    if (schedule.categorySpecificSchedules) {
   633→      for (const [category, categorySchedule] of Object.entries(schedule.categorySpecificSchedules)) {
   634→        if (categorySchedule.template && !validTemplates.includes(categorySchedule.template)) {
   635→          throw new Error(`Template not found for category ${category}: ${categorySchedule.template}`);
   636→        }
   637→      }
   638→    }
   639→  }
