   163→          partialsUsed: [],
   164→          helpersUsed: [],
   165→          emailsProcessed: totalEmailCount,
   166→          categoriesIncluded: groupedCategories.length,
   167→          filteringRules: [],
   168→          sortingCriteria: [request.options?.sortBy || 'date'],
   169→          memoryUsageMB: process.memoryUsage().heapUsed / 1024 / 1024,
   170→          cacheHitRate: 0,
   171→          templateCacheUsed: false,
   172→          contentQualityScore: 1.0,
   173→          templateRenderingErrors: [],
   174→          dataValidationWarnings: [],
   175→        },
   176→      };
   177→
   178→      return digest;
   179→    } catch (error) {
   180→      if (error instanceof Error && error.message.includes('Template')) {
   181→        throw new Error(`Template rendering failed: ${error.message}`);
   182→      }
   183→      throw new Error(`Failed to generate digest: ${error instanceof Error ? error.message : String(error)}`);
   184→    }
   185→  }
   186→
   187→  /**
   188→   * Fetch digest data from database with batched queries
   189→   *
   190→   * Performance optimization: Uses 3 queries total instead of N+1 pattern
   191→   */
   192→  private async fetchDigestData(request: GenerateDigestRequest): Promise<{
   193→    emails: EmailWithClassification[];
   194→    categories: Map<number, CategoryMetadata>;
   195→    urgencyMap: Map<string, string>;
   196→  }> {
   197→    try {
   198→      // Query 1: Fetch all active categories
   199→      const categoryRecords = await this.prisma.category.findMany({
   200→        where: { active: true },
   201→        select: {
   202→          categoryId: true,
   203→          code: true,
   204→          displayName: true,
   205→          description: true,
   206→          priority: true,
   207→          iconClass: true,
   208→          colorScheme: true,
   209→        },
   210→        orderBy: { priority: 'asc' },
   211→      });
   212→
   213→      const categoriesMap = new Map<number, CategoryMetadata>(
   214→        categoryRecords.map((cat) => [
   215→          cat.categoryId,
   216→          {
   217→            categoryId: cat.categoryId,
   218→            code: cat.code,
   219→            displayName: cat.displayName,
   220→            description: cat.description,
   221→            priority: cat.priority,
   222→            iconClass: cat.iconClass,
   223→            colorScheme: cat.colorScheme,
   224→          },
   225→        ])
   226→      );
   227→
   228→      // Query 2: Fetch emails in date range with classifications
   229→      const emailRecords = await this.prisma.gmailMessage.findMany({
   230→        where: {
   231→          receivedAt: {
   232→            gte: request.dateRange.start,
   233→            lte: request.dateRange.end,
   234→          },
   235→        },
   236→        select: {
   237→          messageId: true,
   238→          subject: true,
   239→          fromEmail: true,
   240→          fromRaw: true,
   241→          receivedAt: true,
   242→          bodySnippet: true,
   243→        },
   244→        orderBy: { receivedAt: 'desc' },
   245→      });
   246→
   247→      // Query 3: Fetch all session categories for these emails
   248→      const emailIds = emailRecords.map((email) => email.messageId);
   249→      const sessionCategories = await this.prisma.sessionCategory.findMany({
   250→        where: {
   251→          session: {
   252→            gmailId: { in: emailIds },
   253→          },
   254→        },
   255→        select: {
   256→          session: {
   257→            select: {
   258→              gmailId: true,
   259→              sessionId: true,
   260→            },
   261→          },
   262→          categoryId: true,
   263→          isPrimary: true,
   264→          confidence: true,
   265→          aiClassified: true,
   266→        },
   267→      });
   268→
   269→      // Build map of email ID -> session categories
   270→      const emailCategoriesMap = new Map<string, EmailWithClassification['sessionCategories']>();
   271→      for (const sc of sessionCategories) {
   272→        const gmailId = sc.session.gmailId;
   273→        if (!emailCategoriesMap.has(gmailId)) {
   274→          emailCategoriesMap.set(gmailId, []);
   275→        }
   276→        emailCategoriesMap.get(gmailId)!.push({
   277→          categoryId: sc.categoryId,
   278→          isPrimary: sc.isPrimary,
   279→          confidence: sc.confidence,
   280→          aiClassified: sc.aiClassified,
   281→          sessionId: sc.session.sessionId,
   282→        });
   283→      }
   284→
   285→      // Combine emails with their classifications
   286→      const emails: EmailWithClassification[] = emailRecords.map((email) => ({
   287→        messageId: email.messageId,
   288→        subject: email.subject,
   289→        fromEmail: email.fromEmail,
   290→        fromRaw: email.fromRaw,
   291→        receivedAt: email.receivedAt,
   292→        bodySnippet: email.bodySnippet,
   293→        sessionCategories: emailCategoriesMap.get(email.messageId) || [],
   294→      }));
   295→
   296→      // Query 4: Fetch urgency attributes for all sessions
   297→      const sessionIds = Array.from(new Set(sessionCategories.map((sc) => sc.session.sessionId)));
   298→      const urgencyAttributes = await this.prisma.detectedAttribute.findMany({
   299→        where: {
   300→          sessionId: { in: sessionIds },
   301→          attributeName: 'urgency',
   302→        },
   303→        select: {
   304→          sessionId: true,
   305→          attributeValue: true,
   306→        },
   307→      });
   308→
   309→      // Build map of session ID -> urgency level
   310→      const urgencyMap = new Map<string, string>(
   311→        urgencyAttributes.map((attr) => [attr.sessionId.toString(), attr.attributeValue || 'medium'])
   312→      );
   313→
   314→      return { emails, categories: categoriesMap, urgencyMap };
   315→    } catch (error) {
   316→      throw new Error(`Database query failed: ${error instanceof Error ? error.message : String(error)}`);
   317→    }
   318→  }
   319→
   320→  /**
   321→   * Group emails by category with priority sorting
   322→   */
   323→  private groupEmailsByCategory(
   324→    emails: EmailWithClassification[],
   325→    categories: Map<number, CategoryMetadata>,
   326→    urgencyMap: Map<string, string>,
   327→    request: GenerateDigestRequest
   328→  ): DigestCategory[] {
   329→    // Group emails by primary category
   330→    const categoryGroups = new Map<number, EmailWithClassification[]>();
   331→
   332→    for (const email of emails) {
   333→      // Find primary category classification
   334→      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
   335→      if (!primaryClassification) {
   336→        continue; // Skip unclassified emails
   337→      }
   338→
   339→      const categoryId = primaryClassification.categoryId;
   340→      if (!categoryGroups.has(categoryId)) {
   341→        categoryGroups.set(categoryId, []);
   342→      }
   343→      categoryGroups.get(categoryId)!.push(email);
   344→    }
   345→
   346→    // Build DigestCategory objects sorted by priority
   347→    const digestCategories: DigestCategory[] = [];
   348→
   349→    for (const [categoryId, categoryEmails] of categoryGroups.entries()) {
   350→      const categoryMeta = categories.get(categoryId);
   351→      if (!categoryMeta) {
   352→        continue; // Skip if category metadata missing
   353→      }
   354→
   355→      // Filter by category if specified in request
   356→      if (request.categories && !request.categories.includes(categoryMeta.code)) {
   357→        continue;
   358→      }
   359→
   360→      // Convert to DigestEmail objects
   361→      const digestEmails = this.convertToDigestEmails(categoryEmails, urgencyMap);
   362→
   363→      // Group emails by urgency for template organization
   364→      const emailGroups = this.groupEmailsByUrgency(digestEmails);
   365→
   366→      // Calculate category statistics
   367→      const statistics = this.calculateCategoryStatistics(categoryEmails, digestEmails);
   368→
   369→      // Prepare template data
   370→      const templateData = this.prepareCategoryTemplateData(categoryMeta, digestEmails, emailGroups, statistics);
   371→
   372→      const digestCategory: DigestCategory = {
   373→        categoryName: categoryMeta.code,
   374→        emailCount: categoryEmails.length,
   375→        emails: digestEmails,
   376→        priority: categoryMeta.priority,
   377→        templateData,
   378→        categoryMetadata: {
   379→          averageConfidence: statistics.averageConfidence,
   380→          processingDurationMs: 0, // TODO: Calculate from session data
   381→          aiClassificationUsed: categoryEmails.some((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)),
   382→          urgencyDistribution: this.calculateUrgencyDistribution(digestEmails),
   383→        },
   384→      };
   385→
   386→      digestCategories.push(digestCategory);
   387→    }
   388→
   389→    // Sort categories by priority
   390→    digestCategories.sort((a, b) => a.priority - b.priority);
   391→
   392→    return digestCategories;
   393→  }
   394→
   395→  /**
   396→   * Convert database emails to DigestEmail format
   397→   */
   398→  private convertToDigestEmails(emails: EmailWithClassification[], urgencyMap: Map<string, string>): DigestEmail[] {
   399→    return emails.map((email) => {
   400→      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
   401→      const confidence = primaryClassification?.confidence ? Number(primaryClassification.confidence) : 0.0;
   402→
   403→      // Get all categories for this email (primary + secondary)
   404→      const allCategories = email.sessionCategories.map((sc) => {
   405→        // Note: In a real implementation, we'd look up category code from categoryId
   406→        // For now, using a placeholder
   407→        return `cat-${sc.categoryId}`;
   408→      });
   409→
   410→      // Get urgency level from detected attributes
   411→      const sessionId = primaryClassification?.sessionId.toString();
   412→      const urgency = sessionId ? urgencyMap.get(sessionId) || 'medium' : 'medium';
   413→
   414→      // Escape special characters in subject and snippet
   415→      const escapedSubject = this.escapeHtml(email.subject || '(No Subject)');
   416→      const escapedSnippet = this.escapeHtml((email.bodySnippet || '').substring(0, 150));
   417→
   418→      const digestEmail: DigestEmail = {
   419→        emailId: email.messageId,
   420→        subject: escapedSubject,
   421→        from: email.fromEmail || 'unknown@example.com',
   422→        date: email.receivedAt || new Date(),
   423→        snippet: escapedSnippet,
   424→        confidence,
   425→        categories: allCategories,
   426→        urgency,
   427→        includeFullContent: false,
   428→        customHighlights: [],
   429→        renderingData: this.prepareEmailRenderingData(email, urgency, confidence),
   430→      };
   431→
   432→      return digestEmail;
   433→    });
   434→  }
   435→
   436→  /**
   437→   * Group emails by urgency level for template organization
   438→   */
   439→  private groupEmailsByUrgency(emails: DigestEmail[]): EmailGroup[] {
   440→    const urgentEmails = emails.filter((e) => e.urgency === 'high');
   441→    const normalEmails = emails.filter((e) => e.urgency === 'medium');
   442→    const lowPriorityEmails = emails.filter((e) => e.urgency === 'low');
   443→
   444→    const groups: EmailGroup[] = [];
   445→
   446→    if (urgentEmails.length > 0) {
   447→      groups.push({
   448→        groupType: 'urgent',
   449→        groupName: 'Urgent',
   450→        emails: urgentEmails,
   451→        groupSummary: `${urgentEmails.length} urgent email(s) requiring immediate attention`,
   452→        groupIcon: '🔴',
   453→      });
   454→    }
   455→
   456→    if (normalEmails.length > 0) {
   457→      groups.push({
   458→        groupType: 'normal',
   459→        groupName: 'Normal Priority',
   460→        emails: normalEmails,
   461→        groupSummary: `${normalEmails.length} email(s)`,
   462→        groupIcon: '📧',
   463→      });
   464→    }
   465→
   466→    if (lowPriorityEmails.length > 0) {
   467→      groups.push({
   468→        groupType: 'low_priority',
   469→        groupName: 'Low Priority',
   470→        emails: lowPriorityEmails,
   471→        groupSummary: `${lowPriorityEmails.length} low priority email(s)`,
   472→        groupIcon: '📭',
   473→      });
   474→    }
   475→
   476→    return groups;
   477→  }
   478→
   479→  /**
   480→   * Calculate category statistics for template display
   481→   */
   482→  private calculateCategoryStatistics(
   483→    emails: EmailWithClassification[],
   484→    digestEmails: DigestEmail[]
   485→  ): CategoryStatistics {
   486→    const confidences = emails
   487→      .map((e) => e.sessionCategories.find((sc) => sc.isPrimary)?.confidence)
   488→      .filter((c): c is Prisma.Decimal => c !== undefined && c !== null)
   489→      .map((c) => Number(c));
   490→
   491→    const averageConfidence =
   492→      confidences.length > 0 ? confidences.reduce((sum, c) => sum + c, 0) / confidences.length : 0;
   493→
   494→    const urgentEmailsCount = digestEmails.filter((e) => e.urgency === 'high').length;
   495→
   496→    const aiClassifiedCount = emails.filter((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)).length;
   497→
   498→    // Calculate top domains
   499→    const domainCounts = new Map<string, number>();
   500→    for (const email of emails) {
   501→      if (email.fromEmail) {
   502→        const domain = email.fromEmail.split('@')[1] || email.fromEmail;
   503→        domainCounts.set(domain, (domainCounts.get(domain) || 0) + 1);
   504→      }
   505→    }
   506→
   507→    const topDomains = Array.from(domainCounts.entries())
   508→      .sort((a, b) => b[1] - a[1])
   509→      .slice(0, 5)
   510→      .map(([domain, count]) => ({ domain, count }));
   511→
   512→    return {
   513→      emailCount: emails.length,
   514→      averageConfidence,
   515→      urgentEmailsCount,
   516→      aiClassifiedCount,
   517→      averageProcessingTime: 0, // TODO: Calculate from session metrics
   518→      topDomains,
   519→    };
   520→  }
   521→
   522→  /**
   523→   * Prepare category template data for Handlebars rendering
   524→   */
   525→  private prepareCategoryTemplateData(
   526→    categoryMeta: CategoryMetadata,
   527→    emails: DigestEmail[],
   528→    emailGroups: EmailGroup[],
   529→    statistics: CategoryStatistics
   530→  ): DigestCategoryTemplateData {
   531→    return {
   532→      name: categoryMeta.code,
   533→      displayName: categoryMeta.displayName || categoryMeta.code,
   534→      description: categoryMeta.description || '',
   535→      emailGroups,
   536→      totalCount: emails.length,
   537→      iconClass: categoryMeta.iconClass || 'default-icon',
   538→      colorScheme: categoryMeta.colorScheme || '#333333',
   539→      sortOrder: categoryMeta.priority,
   540→      statistics,
   541→      customVariables: {},
   542→    };
   543→  }
   544→
   545→  /**
   546→   * Prepare email rendering data for templates
   547→   */
   548→  private prepareEmailRenderingData(
   549→    email: EmailWithClassification,
   550→    urgency: string,
   551→    confidence: number
   552→  ): DigestEmailRenderingData {
   553→    return {
   554→      displaySubject: (email.subject || '(No Subject)').substring(0, 100),
   555→      displayFrom: email.fromRaw || email.fromEmail || 'Unknown Sender',
   556→      displayDate: email.receivedAt?.toLocaleDateString() || '',
   557→      displayTime: email.receivedAt?.toLocaleTimeString() || '',
   558→      summarySnippet: (email.bodySnippet || '').substring(0, 150),
   559→      keyHighlights: [],
   560→      actionableItems: [],
   561→      urgencyIcon: urgency === 'high' ? '🔴' : urgency === 'medium' ? '🟡' : '🟢',
   562→      confidenceIndicator: confidence > 0.9 ? 'High' : confidence > 0.7 ? 'Medium' : 'Low',
   563→      categoryBadges: [],
   564→      quickActions: [],
   565→      expandedContentAvailable: false,
   566→    };
   567→  }
   568→
   569→  /**
   570→   * Calculate urgency distribution for category metadata
   571→   */
   572→  private calculateUrgencyDistribution(emails: DigestEmail[]): Record<string, number> {
   573→    const distribution: Record<string, number> = {
   574→      high: 0,
   575→      medium: 0,
   576→      low: 0,
   577→    };
   578→
   579→    for (const email of emails) {
   580→      distribution[email.urgency] = (distribution[email.urgency] || 0) + 1;
   581→    }
   582→
   583→    return distribution;
   584→  }
   585→
   586→  /**
   587→   * Prepare complete template data for Handlebars
   588→   */
   589→  private prepareTemplateData(request: GenerateDigestRequest, categories: DigestCategory[]): Record<string, unknown> {
   590→    return {
   591→      digestType: request.digestType,
   592→      recipientEmail: request.recipientEmail,
   593→      generatedAt: new Date().toISOString(),
   594→      dateRange: {
   595→        start: request.dateRange.start.toISOString(),
   596→        end: request.dateRange.end.toISOString(),
   597→      },
   598→      categories,
   599→      totalEmailCount: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
   600→      summary: {
   601→        totalCategories: categories.length,
   602→        totalEmails: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
   603→        urgentEmails: categories.reduce((sum, cat) => sum + cat.categoryMetadata.urgencyDistribution.high, 0),
   604→      },
   605→    };
   606→  }
   607→
   608→  /**
   609→   * Render HTML using TemplateEngine
   610→   */
   611→  private async renderHTML(request: GenerateDigestRequest, templateData: Record<string, unknown>): Promise<string> {
   612→    try {
   613→      const templateName = request.templateName || `default-${request.digestType}`;
   614→
   615→      // Load template from file system
   616→      const templateContent = this.templateEngine.loadTemplate(templateName);
   617→
   618→      // Compile template with data
   619→      const htmlContent = this.templateEngine.compile(templateContent, templateData);
   620→
   621→      return htmlContent;
   622→    } catch (error) {
   623→      throw new Error(`Template rendering failed: ${error instanceof Error ? error.message : String(error)}`);
   624→    }
   625→  }
   626→
   627→  /**
   628→   * Validate digest generation request
   629→   */
   630→  private validateRequest(request: GenerateDigestRequest): void {
   631→    // Validate date range
   632→    if (request.dateRange.start > request.dateRange.end) {
   633→      throw new Error('Invalid date range: start must be before end');
   634→    }
   635→
   636→    // Validate email format
   637→    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   638→    if (!emailRegex.test(request.recipientEmail)) {
   639→      throw new Error('Invalid recipient email');
   640→    }
   641→
   642→    // Validate digest type
   643→    if (!['daily', 'weekly', 'on_demand'].includes(request.digestType)) {
   644→      throw new Error(`Invalid digest type: ${request.digestType}`);
   645→    }
   646→  }
   647→
   648→  /**
   649→   * Escape HTML special characters to prevent XSS
   650→   */
   651→  private escapeHtml(text: string): string {
   652→    const htmlEscapeMap: Record<string, string> = {
   653→      '&': '&amp;',
   654→      '<': '&lt;',
   655→      '>': '&gt;',
   656→      '"': '&quot;',
   657→      "'": '&#39;',
   658→    };
   659→
   660→    return text.replace(/[&<>"']/g, (char) => htmlEscapeMap[char] || char);
   661→  }
   662→
   663→  /**
   664→   * Close Prisma client connection
   665→   */
   666→  async close(): Promise<void> {
   667→    if (this.ownsPrisma) {
   668→      await this.prisma.$disconnect();
   669→    }
   670→  }
   671→}
