/**
 * Digest Generator Service (T046) - Real Implementation
 *
 * Handles email digest generation with:
 * - Category grouping logic
 * - Template data preparation for Handlebars
 * - HTML generation using TemplateEngine (T045)
 * - Performance optimization with batched database queries
 *
 * Integrates with:
 * - Prisma ORM for database queries
 * - TemplateEngine (T045) for HTML rendering
 * - Classification results from T043 (ClassificationRepository)
 */

import { PrismaClient, Prisma } from '@prisma/client';
import { TemplateEngine } from './template-engine';
import type {
  EmailDigest,
  DigestCategory,
  DigestEmail,
  DigestCategoryTemplateData,
  EmailGroup,
  CategoryStatistics,
  DigestEmailRenderingData,
  DigestGenerationMetadata,
} from '../types/email-digest';
import { randomUUID } from 'crypto';

/**
 * Request parameters for digest generation
 */
export interface GenerateDigestRequest {
  digestType: 'daily' | 'weekly' | 'on_demand';
  dateRange: {
    start: Date;
    end: Date;
  };
  recipientEmail: string;
  templateName?: string;
  categories?: string[]; // Optional category filter
  options?: {
    maxEmailsPerCategory?: number;
    includeFullContent?: boolean;
    sortBy?: 'date' | 'confidence' | 'urgency';
  };
}

/**
 * Internal email data structure from database
 */
interface EmailWithClassification {
  gmailId: string;
  subject: string | null;
  fromSimple: Prisma.JsonValue;
  sentAt: Date;
  bodyText: string | null;
  sessionCategories: Array<{
    categoryId: number;
    isPrimary: boolean;
    confidence: Prisma.Decimal | null;
    aiClassified: boolean | null;
    sessionId: bigint;
  }>;
}

/**
 * Category metadata from database
 */
interface CategoryMetadata {
  categoryId: number;
  code: string;
  displayName: string | null;
  description: string | null;
  priority: number;
  iconClass: string | null;
  colorScheme: string | null;
}

/**
 * Digest Generator Implementation
 *
 * Generates categorized email digests with HTML templates
 */
export class DigestGenerator {
  private readonly prisma: PrismaClient;
  private readonly templateEngine: TemplateEngine;
  private readonly ownsPrisma: boolean;

  /**
   * Initialize DigestGenerator
   *
   * @param prisma - Prisma client instance (creates default if not provided)
   * @param templateEngine - TemplateEngine instance (creates default if not provided)
   */
  constructor(prisma?: PrismaClient, templateEngine?: TemplateEngine) {
    if (prisma) {
      this.prisma = prisma;
      this.ownsPrisma = false;
    } else {
      this.prisma = new PrismaClient();
      this.ownsPrisma = true;
    }

    this.templateEngine = templateEngine || new TemplateEngine();
  }

  /**
   * Generate email digest with category grouping
   *
   * @param request - Digest generation request parameters
   * @returns Complete EmailDigest with categorized emails and HTML content
   * @throws {Error} If validation fails or generation encounters errors
   */
  async generateDigest(request: GenerateDigestRequest): Promise<EmailDigest> {
    const startTime = Date.now();

    // Validate request parameters
    this.validateRequest(request);

    try {
      // Step 1: Fetch data from database (batched queries for performance)
      const dataPreparationStart = Date.now();
      const { emails, categories, urgencyMap } = await this.fetchDigestData(request);
      const dataPreparationTimeMs = Date.now() - dataPreparationStart;

      // Step 2: Group emails by category with priority sorting
      const groupedCategories = this.groupEmailsByCategory(emails, categories, urgencyMap, request);

      // Step 3: Prepare template data for Handlebars
      const templateData = this.prepareTemplateData(request, groupedCategories);

      // Step 4: Render HTML using TemplateEngine
      const templateRenderingStart = Date.now();
      const htmlContent = await this.renderHTML(request, templateData);
      const templateRenderingTimeMs = Date.now() - templateRenderingStart;

      // Step 5: Build complete EmailDigest object
      const totalEmailCount = groupedCategories.reduce((sum, cat) => sum + cat.emailCount, 0);
      const generationDurationMs = Date.now() - startTime;

      const digest: EmailDigest = {
        id: randomUUID(),
        generatedAt: new Date(),
        digestType: request.digestType,
        recipientEmail: request.recipientEmail,
        categories: groupedCategories,
        totalEmailCount,
        dateRange: {
          start: request.dateRange.start,
          end: request.dateRange.end,
        },
        templateUsed: request.templateName || `default-${request.digestType}`,
        htmlContent,
        deliveryStatus: 'pending',
        generationMetadata: {
          generationDurationMs,
          templateRenderingTimeMs,
          dataPreparationTimeMs,
          templateEngine: 'handlebars',
          templateVersion: '1.0.0',
          partialsUsed: [],
          helpersUsed: [],
          emailsProcessed: totalEmailCount,
          categoriesIncluded: groupedCategories.length,
          filteringRules: [],
          sortingCriteria: [request.options?.sortBy || 'date'],
          memoryUsageMB: process.memoryUsage().heapUsed / 1024 / 1024,
          cacheHitRate: 0,
          templateCacheUsed: false,
          contentQualityScore: 1.0,
          templateRenderingErrors: [],
          dataValidationWarnings: [],
        },
      };

      return digest;
    } catch (error) {
      if (error instanceof Error && error.message.includes('Template')) {
        throw new Error(`Template rendering failed: ${error.message}`);
      }
      throw new Error(`Failed to generate digest: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Fetch digest data from database with batched queries
   *
   * Performance optimization: Uses 3 queries total instead of N+1 pattern
   */
  private async fetchDigestData(request: GenerateDigestRequest): Promise<{
    emails: EmailWithClassification[];
    categories: Map<number, CategoryMetadata>;
    urgencyMap: Map<string, string>;
  }> {
    try {
      // Query 1: Fetch all active categories
      const categoryRecords = await this.prisma.category.findMany({
        where: { active: true },
        select: {
          categoryId: true,
          code: true,
          displayName: true,
          description: true,
        },
        orderBy: { categoryId: 'asc' }, // Use categoryId for sorting since priority field doesn't exist yet
      });

      const categoriesMap = new Map<number, CategoryMetadata>(
        categoryRecords.map((cat) => [
          cat.categoryId,
          {
            categoryId: cat.categoryId,
            code: cat.code,
            displayName: cat.displayName,
            description: cat.description,
            priority: cat.categoryId, // Use categoryId as fallback priority
            iconClass: null,
            colorScheme: null,
          },
        ])
      );

      // Query 2: Fetch emails in date range with classifications
      const emailRecords = await this.prisma.gmailMessage.findMany({
        where: {
          sentAt: {
            gte: request.dateRange.start,
            lte: request.dateRange.end,
          },
        },
        select: {
          gmailId: true,
          subject: true,
          fromSimple: true,
          sentAt: true,
          bodyText: true,
        },
        orderBy: { sentAt: 'desc' },
      });

      // Query 3: Fetch all session categories for these emails
      const emailIds = emailRecords.map((email) => email.gmailId);
      const sessionCategories = await this.prisma.sessionCategory.findMany({
        where: {
          session: {
            gmailId: { in: emailIds },
          },
        },
        select: {
          session: {
            select: {
              gmailId: true,
              sessionId: true,
            },
          },
          categoryId: true,
          isPrimary: true,
          confidence: true,
          aiClassified: true,
        },
      });

      // Build map of email ID -> session categories
      const emailCategoriesMap = new Map<string, EmailWithClassification['sessionCategories']>();
      for (const sc of sessionCategories) {
        const gmailId = sc.session.gmailId;
        if (!emailCategoriesMap.has(gmailId)) {
          emailCategoriesMap.set(gmailId, []);
        }
        emailCategoriesMap.get(gmailId)!.push({
          categoryId: sc.categoryId,
          isPrimary: sc.isPrimary,
          confidence: sc.confidence,
          aiClassified: sc.aiClassified,
          sessionId: sc.session.sessionId,
        });
      }

      // Combine emails with their classifications
      const emails: EmailWithClassification[] = emailRecords.map((email) => ({
        gmailId: email.gmailId,
        subject: email.subject,
        fromSimple: email.fromSimple,
        sentAt: email.sentAt,
        bodyText: email.bodyText,
        sessionCategories: emailCategoriesMap.get(email.gmailId) || [],
      }));

      // Query 4: Fetch urgency attributes for all sessions
      const sessionIds = Array.from(new Set(sessionCategories.map((sc) => sc.session.sessionId)));
      const urgencyAttributes = await this.prisma.detectedAttribute.findMany({
        where: {
          sessionId: { in: sessionIds },
          attributeName: 'urgency',
        },
        select: {
          sessionId: true,
          attributeValue: true,
        },
      });

      // Build map of session ID -> urgency level
      const urgencyMap = new Map<string, string>(
        urgencyAttributes.map((attr) => [attr.sessionId.toString(), attr.attributeValue || 'medium'])
      );

      return { emails, categories: categoriesMap, urgencyMap };
    } catch (error) {
      throw new Error(`Database query failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Group emails by category with priority sorting
   */
  private groupEmailsByCategory(
    emails: EmailWithClassification[],
    categories: Map<number, CategoryMetadata>,
    urgencyMap: Map<string, string>,
    request: GenerateDigestRequest
  ): DigestCategory[] {
    // Group emails by primary category
    const categoryGroups = new Map<number, EmailWithClassification[]>();

    for (const email of emails) {
      // Find primary category classification
      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
      if (!primaryClassification) {
        continue; // Skip unclassified emails
      }

      const categoryId = primaryClassification.categoryId;
      if (!categoryGroups.has(categoryId)) {
        categoryGroups.set(categoryId, []);
      }
      categoryGroups.get(categoryId)!.push(email);
    }

    // Build DigestCategory objects sorted by priority
    const digestCategories: DigestCategory[] = [];

    for (const [categoryId, categoryEmails] of categoryGroups.entries()) {
      const categoryMeta = categories.get(categoryId);
      if (!categoryMeta) {
        continue; // Skip if category metadata missing
      }

      // Filter by category if specified in request
      if (request.categories && !request.categories.includes(categoryMeta.code)) {
        continue;
      }

      // Convert to DigestEmail objects
      const digestEmails = this.convertToDigestEmails(categoryEmails, urgencyMap);

      // Group emails by urgency for template organization
      const emailGroups = this.groupEmailsByUrgency(digestEmails);

      // Calculate category statistics
      const statistics = this.calculateCategoryStatistics(categoryEmails, digestEmails);

      // Prepare template data
      const templateData = this.prepareCategoryTemplateData(categoryMeta, digestEmails, emailGroups, statistics);

      const digestCategory: DigestCategory = {
        categoryName: categoryMeta.code,
        emailCount: categoryEmails.length,
        emails: digestEmails,
        priority: categoryMeta.priority,
        templateData,
        categoryMetadata: {
          averageConfidence: statistics.averageConfidence,
          processingDurationMs: 0, // TODO: Calculate from session data
          aiClassificationUsed: categoryEmails.some((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)),
          urgencyDistribution: this.calculateUrgencyDistribution(digestEmails),
        },
      };

      digestCategories.push(digestCategory);
    }

    // Sort categories by priority
    digestCategories.sort((a, b) => a.priority - b.priority);

    return digestCategories;
  }

  /**
   * Convert database emails to DigestEmail format
   */
  private convertToDigestEmails(emails: EmailWithClassification[], urgencyMap: Map<string, string>): DigestEmail[] {
    return emails.map((email) => {
      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
      const confidence = primaryClassification?.confidence ? Number(primaryClassification.confidence) : 0.0;

      // Get all categories for this email (primary + secondary)
      const allCategories = email.sessionCategories.map((sc) => {
        // Note: In a real implementation, we'd look up category code from categoryId
        // For now, using a placeholder
        return `cat-${sc.categoryId}`;
      });

      // Get urgency level from detected attributes
      const sessionId = primaryClassification?.sessionId.toString();
      const urgency = sessionId ? urgencyMap.get(sessionId) || 'medium' : 'medium';

      // Extract email from fromSimple JSON (expected format: [{"email": "user@example.com"}])
      const fromEmail = this.extractEmailFromJson(email.fromSimple);

      // Escape special characters in subject and snippet
      const escapedSubject = this.escapeHtml(email.subject || '(No Subject)');
      const escapedSnippet = this.escapeHtml((email.bodyText || '').substring(0, 150));

      const digestEmail: DigestEmail = {
        emailId: email.gmailId,
        subject: escapedSubject,
        from: fromEmail,
        date: email.sentAt,
        snippet: escapedSnippet,
        confidence,
        categories: allCategories,
        urgency,
        includeFullContent: false,
        customHighlights: [],
        renderingData: this.prepareEmailRenderingData(email, urgency, confidence),
      };

      return digestEmail;
    });
  }

  /**
   * Group emails by urgency level for template organization
   */
  private groupEmailsByUrgency(emails: DigestEmail[]): EmailGroup[] {
    const urgentEmails = emails.filter((e) => e.urgency === 'high');
    const normalEmails = emails.filter((e) => e.urgency === 'medium');
    const lowPriorityEmails = emails.filter((e) => e.urgency === 'low');

    const groups: EmailGroup[] = [];

    if (urgentEmails.length > 0) {
      groups.push({
        groupType: 'urgent',
        groupName: 'Urgent',
        emails: urgentEmails,
        groupSummary: `${urgentEmails.length} urgent email(s) requiring immediate attention`,
        groupIcon: '🔴',
      });
    }

    if (normalEmails.length > 0) {
      groups.push({
        groupType: 'normal',
        groupName: 'Normal Priority',
        emails: normalEmails,
        groupSummary: `${normalEmails.length} email(s)`,
        groupIcon: '📧',
      });
    }

    if (lowPriorityEmails.length > 0) {
      groups.push({
        groupType: 'low_priority',
        groupName: 'Low Priority',
        emails: lowPriorityEmails,
        groupSummary: `${lowPriorityEmails.length} low priority email(s)`,
        groupIcon: '📭',
      });
    }

    return groups;
  }

  /**
   * Calculate category statistics for template display
   */
  private calculateCategoryStatistics(
    emails: EmailWithClassification[],
    digestEmails: DigestEmail[]
  ): CategoryStatistics {
    const confidences = emails
      .map((e) => e.sessionCategories.find((sc) => sc.isPrimary)?.confidence)
      .filter((c): c is Prisma.Decimal => c !== undefined && c !== null)
      .map((c) => Number(c));

    const averageConfidence =
      confidences.length > 0 ? confidences.reduce((sum, c) => sum + c, 0) / confidences.length : 0;

    const urgentEmailsCount = digestEmails.filter((e) => e.urgency === 'high').length;

    const aiClassifiedCount = emails.filter((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)).length;

    // Calculate top domains
    const domainCounts = new Map<string, number>();
    for (const email of emails) {
      const fromEmail = this.extractEmailFromJson(email.fromSimple);
      const domain = fromEmail.split('@')[1] || fromEmail;
      domainCounts.set(domain, (domainCounts.get(domain) || 0) + 1);
    }

    const topDomains = Array.from(domainCounts.entries())
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5)
      .map(([domain, count]) => ({ domain, count }));

    return {
      emailCount: emails.length,
      averageConfidence,
      urgentEmailsCount,
      aiClassifiedCount,
      averageProcessingTime: 0, // TODO: Calculate from session metrics
      topDomains,
    };
  }

  /**
   * Prepare category template data for Handlebars rendering
   */
  private prepareCategoryTemplateData(
    categoryMeta: CategoryMetadata,
    emails: DigestEmail[],
    emailGroups: EmailGroup[],
    statistics: CategoryStatistics
  ): DigestCategoryTemplateData {
    return {
      name: categoryMeta.code,
      displayName: categoryMeta.displayName || categoryMeta.code,
      description: categoryMeta.description || '',
      emailGroups,
      totalCount: emails.length,
      iconClass: categoryMeta.iconClass || 'default-icon',
      colorScheme: categoryMeta.colorScheme || '#333333',
      sortOrder: categoryMeta.priority,
      statistics,
      customVariables: {},
    };
  }

  /**
   * Prepare email rendering data for templates
   */
  private prepareEmailRenderingData(
    email: EmailWithClassification,
    urgency: string,
    confidence: number
  ): DigestEmailRenderingData {
    const fromEmail = this.extractEmailFromJson(email.fromSimple);
    return {
      displaySubject: (email.subject || '(No Subject)').substring(0, 100),
      displayFrom: fromEmail,
      displayDate: email.sentAt.toLocaleDateString(),
      displayTime: email.sentAt.toLocaleTimeString(),
      summarySnippet: (email.bodyText || '').substring(0, 150),
      keyHighlights: [],
      actionableItems: [],
      urgencyIcon: urgency === 'high' ? '🔴' : urgency === 'medium' ? '🟡' : '🟢',
      confidenceIndicator: confidence > 0.9 ? 'High' : confidence > 0.7 ? 'Medium' : 'Low',
      categoryBadges: [],
      quickActions: [],
      expandedContentAvailable: false,
    };
  }

  /**
   * Extract email address from Prisma JSON field
   * Expected format: [{"email": "user@example.com"}] or {"email": "user@example.com"}
   */
  private extractEmailFromJson(jsonValue: Prisma.JsonValue): string {
    try {
      if (Array.isArray(jsonValue) && jsonValue.length > 0) {
        const firstItem = jsonValue[0] as { email?: string };
        return firstItem.email || 'unknown@example.com';
      } else if (typeof jsonValue === 'object' && jsonValue !== null && 'email' in jsonValue) {
        return (jsonValue as { email?: string }).email || 'unknown@example.com';
      }
      return 'unknown@example.com';
    } catch {
      return 'unknown@example.com';
    }
  }

  /**
   * Calculate urgency distribution for category metadata
   */
  private calculateUrgencyDistribution(emails: DigestEmail[]): Record<string, number> {
    const distribution: Record<string, number> = {
      high: 0,
      medium: 0,
      low: 0,
    };

    for (const email of emails) {
      distribution[email.urgency] = (distribution[email.urgency] || 0) + 1;
    }

    return distribution;
  }

  /**
   * Prepare complete template data for Handlebars
   */
  private prepareTemplateData(request: GenerateDigestRequest, categories: DigestCategory[]): Record<string, unknown> {
    return {
      digestType: request.digestType,
      recipientEmail: request.recipientEmail,
      generatedAt: new Date().toISOString(),
      dateRange: {
        start: request.dateRange.start.toISOString(),
        end: request.dateRange.end.toISOString(),
      },
      categories,
      totalEmailCount: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
      summary: {
        totalCategories: categories.length,
        totalEmails: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
        urgentEmails: categories.reduce((sum, cat) => sum + cat.categoryMetadata.urgencyDistribution.high, 0),
      },
    };
  }

  /**
   * Render HTML using TemplateEngine
   */
  private async renderHTML(request: GenerateDigestRequest, templateData: Record<string, unknown>): Promise<string> {
    try {
      const templateName = request.templateName || `default-${request.digestType}`;

      // Load template from file system
      const templateContent = this.templateEngine.loadTemplate(templateName);

      // Compile template with data
      const htmlContent = this.templateEngine.compile(templateContent, templateData);

      return htmlContent;
    } catch (error) {
      throw new Error(`Template rendering failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Validate digest generation request
   */
  private validateRequest(request: GenerateDigestRequest): void {
    // Validate date range
    if (request.dateRange.start > request.dateRange.end) {
      throw new Error('Invalid date range: start must be before end');
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(request.recipientEmail)) {
      throw new Error('Invalid recipient email');
    }

    // Validate digest type
    if (!['daily', 'weekly', 'on_demand'].includes(request.digestType)) {
      throw new Error(`Invalid digest type: ${request.digestType}`);
    }
  }

  /**
   * Escape HTML special characters to prevent XSS
   */
  private escapeHtml(text: string): string {
    const htmlEscapeMap: Record<string, string> = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#39;',
    };

    return text.replace(/[&<>"']/g, (char) => htmlEscapeMap[char] || char);
  }

  /**
   * Close Prisma client connection
   */
  async close(): Promise<void> {
    if (this.ownsPrisma) {
      await this.prisma.$disconnect();
    }
  }
}

