   133→      // Step 4: Render HTML using TemplateEngine
   134→      const templateRenderingStart = Date.now();
   135→      const htmlContent = await this.renderHTML(request, templateData);
   136→      const templateRenderingTimeMs = Date.now() - templateRenderingStart;
   137→
   138→      // Step 5: Build complete EmailDigest object
   139→      const totalEmailCount = groupedCategories.reduce((sum, cat) => sum + cat.emailCount, 0);
   140→      const generationDurationMs = Date.now() - startTime;
   141→
   142→      const digest: EmailDigest = {
   143→        id: randomUUID(),
   144→        generatedAt: new Date(),
   145→        digestType: request.digestType,
   146→        recipientEmail: request.recipientEmail,
   147→        categories: groupedCategories,
   148→        totalEmailCount,
   149→        dateRange: {
   150→          start: request.dateRange.start,
   151→          end: request.dateRange.end,
   152→        },
   153→        templateUsed: request.templateName || `default-${request.digestType}`,
   154→        htmlContent,
   155→        deliveryStatus: 'pending',
   156→        generationMetadata: {
   157→          generationDurationMs,
   158→          templateRenderingTimeMs,
   159→          dataPreparationTimeMs,
   160→          templateEngine: 'handlebars',
   161→          templateVersion: '1.0.0',
   162→          partialsUsed: [],
   163→          helpersUsed: [],
   164→          emailsProcessed: totalEmailCount,
   165→          categoriesIncluded: groupedCategories.length,
   166→          filteringRules: [],
   167→          sortingCriteria: [request.options?.sortBy || 'date'],
   168→          memoryUsageMB: process.memoryUsage().heapUsed / 1024 / 1024,
   169→          cacheHitRate: 0,
   170→          templateCacheUsed: false,
   171→          contentQualityScore: 1.0,
   172→          templateRenderingErrors: [],
   173→          dataValidationWarnings: [],
   174→        },
   175→      };
   176→
   177→      return digest;
   178→    } catch (error) {
   179→      if (error instanceof Error && error.message.includes('Template')) {
   180→        throw new Error(`Template rendering failed: ${error.message}`);
   181→      }
   182→      throw new Error(`Failed to generate digest: ${error instanceof Error ? error.message : String(error)}`);
   183→    }
   184→  }
   185→
   186→  /**
   187→   * Fetch digest data from database with batched queries
   188→   *
   189→   * Performance optimization: Uses 3 queries total instead of N+1 pattern
   190→   */
   191→  private async fetchDigestData(request: GenerateDigestRequest): Promise<{
   192→    emails: EmailWithClassification[];
   193→    categories: Map<number, CategoryMetadata>;
   194→    urgencyMap: Map<string, string>;
   195→  }> {
   196→    try {
   197→      // Query 1: Fetch all active categories
   198→      const categoryRecords = await this.prisma.category.findMany({
   199→        where: { active: true },
   200→        select: {
   201→          categoryId: true,
   202→          code: true,
   203→          displayName: true,
   204→          description: true,
   205→        },
   206→        orderBy: { categoryId: 'asc' }, // Use categoryId for sorting since priority field doesn't exist yet
   207→      });
   208→
   209→      const categoriesMap = new Map<number, CategoryMetadata>(
   210→        categoryRecords.map((cat) => [
   211→          cat.categoryId,
   212→          {
   213→            categoryId: cat.categoryId,
   214→            code: cat.code,
   215→            displayName: cat.displayName,
   216→            description: cat.description,
   217→            priority: cat.categoryId, // Use categoryId as fallback priority
   218→            iconClass: null,
   219→            colorScheme: null,
   220→          },
   221→        ])
   222→      );
   223→
   224→      // Query 2: Fetch emails in date range with classifications
   225→      const emailRecords = await this.prisma.gmailMessage.findMany({
   226→        where: {
   227→          sentAt: {
   228→            gte: request.dateRange.start,
   229→            lte: request.dateRange.end,
   230→          },
   231→        },
   232→        select: {
   233→          gmailId: true,
   234→          subject: true,
   235→          fromSimple: true,
   236→          sentAt: true,
   237→          bodyText: true,
   238→        },
   239→        orderBy: { sentAt: 'desc' },
   240→      });
   241→
   242→      // Query 3: Fetch all session categories for these emails
   243→      const emailIds = emailRecords.map((email) => email.gmailId);
   244→      const sessionCategories = await this.prisma.sessionCategory.findMany({
   245→        where: {
   246→          session: {
   247→            gmailId: { in: emailIds },
   248→          },
   249→        },
   250→        select: {
   251→          session: {
   252→            select: {
   253→              gmailId: true,
   254→              sessionId: true,
   255→            },
   256→          },
   257→          categoryId: true,
   258→          isPrimary: true,
   259→          confidence: true,
   260→          aiClassified: true,
   261→        },
   262→      });
   263→
   264→      // Build map of email ID -> session categories
   265→      const emailCategoriesMap = new Map<string, EmailWithClassification['sessionCategories']>();
   266→      for (const sc of sessionCategories) {
   267→        const gmailId = sc.session.gmailId;
   268→        if (!emailCategoriesMap.has(gmailId)) {
   269→          emailCategoriesMap.set(gmailId, []);
   270→        }
   271→        emailCategoriesMap.get(gmailId)!.push({
   272→          categoryId: sc.categoryId,
   273→          isPrimary: sc.isPrimary,
   274→          confidence: sc.confidence,
   275→          aiClassified: sc.aiClassified,
   276→          sessionId: sc.session.sessionId,
   277→        });
   278→      }
   279→
   280→      // Combine emails with their classifications
   281→      const emails: EmailWithClassification[] = emailRecords.map((email) => ({
   282→        gmailId: email.gmailId,
   283→        subject: email.subject,
   284→        fromSimple: email.fromSimple,
   285→        sentAt: email.sentAt,
   286→        bodyText: email.bodyText,
   287→        sessionCategories: emailCategoriesMap.get(email.gmailId) || [],
   288→      }));
   289→
   290→      // Query 4: Fetch urgency attributes for all sessions
   291→      const sessionIds = Array.from(new Set(sessionCategories.map((sc) => sc.session.sessionId)));
   292→      const urgencyAttributes = await this.prisma.detectedAttribute.findMany({
   293→        where: {
   294→          sessionId: { in: sessionIds },
   295→          attributeName: 'urgency',
   296→        },
   297→        select: {
   298→          sessionId: true,
   299→          attributeValue: true,
   300→        },
   301→      });
   302→
   303→      // Build map of session ID -> urgency level
   304→      const urgencyMap = new Map<string, string>(
   305→        urgencyAttributes.map((attr) => [attr.sessionId.toString(), attr.attributeValue || 'medium'])
   306→      );
   307→
   308→      return { emails, categories: categoriesMap, urgencyMap };
   309→    } catch (error) {
   310→      throw new Error(`Database query failed: ${error instanceof Error ? error.message : String(error)}`);
   311→    }
   312→  }
   313→
   314→  /**
   315→   * Group emails by category with priority sorting
   316→   */
   317→  private groupEmailsByCategory(
   318→    emails: EmailWithClassification[],
   319→    categories: Map<number, CategoryMetadata>,
   320→    urgencyMap: Map<string, string>,
   321→    request: GenerateDigestRequest
   322→  ): DigestCategory[] {
   323→    // Group emails by primary category
   324→    const categoryGroups = new Map<number, EmailWithClassification[]>();
   325→
   326→    for (const email of emails) {
   327→      // Find primary category classification
   328→      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
   329→      if (!primaryClassification) {
   330→        continue; // Skip unclassified emails
   331→      }
   332→
   333→      const categoryId = primaryClassification.categoryId;
   334→      if (!categoryGroups.has(categoryId)) {
   335→        categoryGroups.set(categoryId, []);
   336→      }
   337→      categoryGroups.get(categoryId)!.push(email);
   338→    }
   339→
   340→    // Build DigestCategory objects sorted by priority
   341→    const digestCategories: DigestCategory[] = [];
   342→
   343→    for (const [categoryId, categoryEmails] of Array.from(categoryGroups.entries())) {
   344→      const categoryMeta = categories.get(categoryId);
   345→      if (!categoryMeta) {
   346→        continue; // Skip if category metadata missing
   347→      }
   348→
   349→      // Filter by category if specified in request
   350→      if (request.categories && !request.categories.includes(categoryMeta.code)) {
   351→        continue;
   352→      }
   353→
   354→      // Convert to DigestEmail objects
   355→      const digestEmails = this.convertToDigestEmails(categoryEmails, urgencyMap);
   356→
   357→      // Group emails by urgency for template organization
   358→      const emailGroups = this.groupEmailsByUrgency(digestEmails);
   359→
   360→      // Calculate category statistics
   361→      const statistics = this.calculateCategoryStatistics(categoryEmails, digestEmails);
   362→
   363→      // Prepare template data
   364→      const templateData = this.prepareCategoryTemplateData(categoryMeta, digestEmails, emailGroups, statistics);
   365→
   366→      const digestCategory: DigestCategory = {
   367→        categoryName: categoryMeta.code,
   368→        emailCount: categoryEmails.length,
   369→        emails: digestEmails,
   370→        priority: categoryMeta.priority,
   371→        templateData,
   372→        categoryMetadata: {
   373→          averageConfidence: statistics.averageConfidence,
   374→          processingDurationMs: 0, // TODO: Calculate from session data
   375→          aiClassificationUsed: categoryEmails.some((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)),
   376→          urgencyDistribution: this.calculateUrgencyDistribution(digestEmails),
   377→        },
   378→      };
   379→
   380→      digestCategories.push(digestCategory);
   381→    }
   382→
   383→    // Sort categories by priority
   384→    digestCategories.sort((a, b) => a.priority - b.priority);
   385→
   386→    return digestCategories;
   387→  }
   388→
   389→  /**
   390→   * Convert database emails to DigestEmail format
   391→   */
   392→  private convertToDigestEmails(emails: EmailWithClassification[], urgencyMap: Map<string, string>): DigestEmail[] {
   393→    return emails.map((email) => {
   394→      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
   395→      const confidence = primaryClassification?.confidence ? Number(primaryClassification.confidence) : 0.0;
   396→
   397→      // Get all categories for this email (primary + secondary)
   398→      const allCategories = email.sessionCategories.map((sc) => {
   399→        // Note: In a real implementation, we'd look up category code from categoryId
   400→        // For now, using a placeholder
   401→        return `cat-${sc.categoryId}`;
   402→      });
   403→
   404→      // Get urgency level from detected attributes
   405→      const sessionId = primaryClassification?.sessionId.toString();
   406→      const urgency = sessionId ? urgencyMap.get(sessionId) || 'medium' : 'medium';
   407→
   408→      // Extract email from fromSimple JSON (expected format: [{"email": "user@example.com"}])
   409→      const fromEmail = this.extractEmailFromJson(email.fromSimple);
   410→
   411→      // Escape special characters in subject and snippet
   412→      const escapedSubject = this.escapeHtml(email.subject || '(No Subject)');
   413→      const escapedSnippet = this.escapeHtml((email.bodyText || '').substring(0, 150));
   414→
   415→      const digestEmail: DigestEmail = {
   416→        emailId: email.gmailId,
   417→        subject: escapedSubject,
   418→        from: fromEmail,
   419→        date: email.sentAt,
   420→        snippet: escapedSnippet,
   421→        confidence,
   422→        categories: allCategories,
   423→        urgency,
   424→        includeFullContent: false,
   425→        customHighlights: [],
   426→        renderingData: this.prepareEmailRenderingData(email, urgency, confidence),
   427→      };
   428→
   429→      return digestEmail;
   430→    });
   431→  }
   432→
   433→  /**
   434→   * Group emails by urgency level for template organization
   435→   */
   436→  private groupEmailsByUrgency(emails: DigestEmail[]): EmailGroup[] {
   437→    const urgentEmails = emails.filter((e) => e.urgency === 'high');
   438→    const normalEmails = emails.filter((e) => e.urgency === 'medium');
   439→    const lowPriorityEmails = emails.filter((e) => e.urgency === 'low');
   440→
   441→    const groups: EmailGroup[] = [];
   442→
   443→    if (urgentEmails.length > 0) {
   444→      groups.push({
   445→        groupType: 'urgent',
   446→        groupName: 'Urgent',
   447→        emails: urgentEmails,
   448→        groupSummary: `${urgentEmails.length} urgent email(s) requiring immediate attention`,
   449→        groupIcon: '🔴',
   450→      });
   451→    }
   452→
   453→    if (normalEmails.length > 0) {
   454→      groups.push({
   455→        groupType: 'normal',
   456→        groupName: 'Normal Priority',
   457→        emails: normalEmails,
   458→        groupSummary: `${normalEmails.length} email(s)`,
   459→        groupIcon: '📧',
   460→      });
   461→    }
   462→
   463→    if (lowPriorityEmails.length > 0) {
   464→      groups.push({
   465→        groupType: 'low_priority',
   466→        groupName: 'Low Priority',
   467→        emails: lowPriorityEmails,
   468→        groupSummary: `${lowPriorityEmails.length} low priority email(s)`,
   469→        groupIcon: '📭',
   470→      });
   471→    }
   472→
   473→    return groups;
   474→  }
   475→
   476→  /**
   477→   * Calculate category statistics for template display
   478→   */
   479→  private calculateCategoryStatistics(
   480→    emails: EmailWithClassification[],
   481→    digestEmails: DigestEmail[]
   482→  ): CategoryStatistics {
   483→    const confidences = emails
   484→      .map((e) => e.sessionCategories.find((sc) => sc.isPrimary)?.confidence)
   485→      .filter((c): c is Prisma.Decimal => c !== undefined && c !== null)
   486→      .map((c) => Number(c));
   487→
   488→    const averageConfidence =
   489→      confidences.length > 0 ? confidences.reduce((sum, c) => sum + c, 0) / confidences.length : 0;
   490→
   491→    const urgentEmailsCount = digestEmails.filter((e) => e.urgency === 'high').length;
   492→
   493→    const aiClassifiedCount = emails.filter((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)).length;
   494→
   495→    // Calculate top domains
   496→    const domainCounts = new Map<string, number>();
   497→    for (const email of emails) {
   498→      const fromEmail = this.extractEmailFromJson(email.fromSimple);
   499→      const domain = fromEmail.split('@')[1] || fromEmail;
   500→      domainCounts.set(domain, (domainCounts.get(domain) || 0) + 1);
   501→    }
   502→
   503→    const topDomains = Array.from(domainCounts.entries())
   504→      .sort((a, b) => b[1] - a[1])
   505→      .slice(0, 5)
   506→      .map(([domain, count]) => ({ domain, count }));
   507→
   508→    return {
   509→      emailCount: emails.length,
   510→      averageConfidence,
   511→      urgentEmailsCount,
   512→      aiClassifiedCount,
   513→      averageProcessingTime: 0, // TODO: Calculate from session metrics
   514→      topDomains,
   515→    };
   516→  }
   517→
   518→  /**
   519→   * Prepare category template data for Handlebars rendering
   520→   */
   521→  private prepareCategoryTemplateData(
   522→    categoryMeta: CategoryMetadata,
   523→    emails: DigestEmail[],
   524→    emailGroups: EmailGroup[],
   525→    statistics: CategoryStatistics
   526→  ): DigestCategoryTemplateData {
   527→    return {
   528→      name: categoryMeta.code,
   529→      displayName: categoryMeta.displayName || categoryMeta.code,
   530→      description: categoryMeta.description || '',
   531→      emailGroups,
   532→      totalCount: emails.length,
   533→      iconClass: categoryMeta.iconClass || 'default-icon',
   534→      colorScheme: categoryMeta.colorScheme || '#333333',
   535→      sortOrder: categoryMeta.priority,
   536→      statistics,
   537→      customVariables: {},
   538→    };
   539→  }
   540→
   541→  /**
   542→   * Prepare email rendering data for templates
   543→   */
   544→  private prepareEmailRenderingData(
   545→    email: EmailWithClassification,
   546→    urgency: string,
   547→    confidence: number
   548→  ): DigestEmailRenderingData {
   549→    const fromEmail = this.extractEmailFromJson(email.fromSimple);
   550→    return {
   551→      displaySubject: (email.subject || '(No Subject)').substring(0, 100),
   552→      displayFrom: fromEmail,
   553→      displayDate: email.sentAt.toLocaleDateString(),
   554→      displayTime: email.sentAt.toLocaleTimeString(),
   555→      summarySnippet: (email.bodyText || '').substring(0, 150),
   556→      keyHighlights: [],
   557→      actionableItems: [],
   558→      urgencyIcon: urgency === 'high' ? '🔴' : urgency === 'medium' ? '🟡' : '🟢',
   559→      confidenceIndicator: confidence > 0.9 ? 'High' : confidence > 0.7 ? 'Medium' : 'Low',
   560→      categoryBadges: [],
   561→      quickActions: [],
   562→      expandedContentAvailable: false,
   563→    };
   564→  }
   565→
   566→  /**
   567→   * Extract email address from Prisma JSON field
   568→   * Expected format: [{"email": "user@example.com"}] or {"email": "user@example.com"}
   569→   */
   570→  private extractEmailFromJson(jsonValue: Prisma.JsonValue): string {
   571→    try {
   572→      if (Array.isArray(jsonValue) && jsonValue.length > 0) {
   573→        const firstItem = jsonValue[0] as { email?: string };
   574→        return firstItem.email || 'unknown@example.com';
   575→      } else if (typeof jsonValue === 'object' && jsonValue !== null && 'email' in jsonValue) {
   576→        return (jsonValue as { email?: string }).email || 'unknown@example.com';
   577→      }
   578→      return 'unknown@example.com';
   579→    } catch {
   580→      return 'unknown@example.com';
   581→    }
   582→  }
   583→
   584→  /**
   585→   * Calculate urgency distribution for category metadata
   586→   */
   587→  private calculateUrgencyDistribution(emails: DigestEmail[]): Record<string, number> {
   588→    const distribution: Record<string, number> = {
   589→      high: 0,
   590→      medium: 0,
   591→      low: 0,
   592→    };
   593→
   594→    for (const email of emails) {
   595→      distribution[email.urgency] = (distribution[email.urgency] || 0) + 1;
   596→    }
   597→
   598→    return distribution;
   599→  }
   600→
   601→  /**
   602→   * Prepare complete template data for Handlebars
   603→   */
   604→  private prepareTemplateData(request: GenerateDigestRequest, categories: DigestCategory[]): Record<string, unknown> {
   605→    return {
   606→      digestType: request.digestType,
   607→      recipientEmail: request.recipientEmail,
   608→      generatedAt: new Date().toISOString(),
   609→      dateRange: {
   610→        start: request.dateRange.start.toISOString(),
   611→        end: request.dateRange.end.toISOString(),
   612→      },
   613→      categories,
   614→      totalEmailCount: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
   615→      summary: {
   616→        totalCategories: categories.length,
   617→        totalEmails: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
   618→        urgentEmails: categories.reduce((sum, cat) => sum + cat.categoryMetadata.urgencyDistribution.high, 0),
   619→      },
   620→    };
   621→  }
   622→
   623→  /**
   624→   * Render HTML using TemplateEngine
   625→   */
   626→  private async renderHTML(request: GenerateDigestRequest, templateData: Record<string, unknown>): Promise<string> {
   627→    try {
   628→      const templateName = request.templateName || `default-${request.digestType}`;
   629→
   630→      // For now, use a simple template string. In production, this would load from file system
   631→      const templateContent = this.getDefaultTemplate(templateName);
   632→
   633→      // Compile template with data
   634→      const htmlContent = this.templateEngine.compile(templateContent, templateData);
   635→
   636→      return htmlContent;
   637→    } catch (error) {
   638→      throw new Error(`Template rendering failed: ${error instanceof Error ? error.message : String(error)}`);
   639→    }
   640→  }
   641→
   642→  /**
   643→   * Get default template content
   644→   * TODO: Load from file system in production
   645→   */
   646→  private getDefaultTemplate(templateName: string): string {
   647→    return `
   648→<!DOCTYPE html>
   649→<html>
   650→<head>
   651→  <title>Email Digest - {{digestType}}</title>
   652→  <style>
   653→    body { font-family: Arial, sans-serif; margin: 20px; }
   654→    .category { margin-bottom: 30px; }
   655→    .email { padding: 10px; border-bottom: 1px solid #ccc; }
   656→  </style>
   657→</head>
   658→<body>
   659→  <h1>{{digestType}} Email Digest</h1>
   660→  <p>Generated: {{generatedAt}}</p>
   661→  <p>Total Emails: {{totalEmailCount}}</p>
   662→
   663→  {{#each categories}}
   664→  <div class="category">
   665→    <h2>{{templateData.displayName}}</h2>
   666→    <p>{{emailCount}} emails</p>
   667→  </div>
   668→  {{/each}}
   669→</body>
   670→</html>
   671→    `.trim();
   672→  }
   673→
   674→  /**
   675→   * Validate digest generation request
   676→   */
   677→  private validateRequest(request: GenerateDigestRequest): void {
   678→    // Validate date range
   679→    if (request.dateRange.start > request.dateRange.end) {
   680→      throw new Error('Invalid date range: start must be before end');
   681→    }
   682→
   683→    // Validate email format
   684→    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   685→    if (!emailRegex.test(request.recipientEmail)) {
   686→      throw new Error('Invalid recipient email');
   687→    }
   688→
   689→    // Validate digest type
   690→    if (!['daily', 'weekly', 'on_demand'].includes(request.digestType)) {
   691→      throw new Error(`Invalid digest type: ${request.digestType}`);
   692→    }
   693→  }
   694→
   695→  /**
   696→   * Escape HTML special characters to prevent XSS
   697→   */
   698→  private escapeHtml(text: string): string {
   699→    const htmlEscapeMap: Record<string, string> = {
   700→      '&': '&amp;',
   701→      '<': '&lt;',
   702→      '>': '&gt;',
   703→      '"': '&quot;',
   704→      "'": '&#39;',
   705→    };
   706→
   707→    return text.replace(/[&<>"']/g, (char) => htmlEscapeMap[char] || char);
   708→  }
   709→
   710→  /**
   711→   * Close Prisma client connection
   712→   */
   713→  async close(): Promise<void> {
   714→    if (this.ownsPrisma) {
   715→      await this.prisma.$disconnect();
   716→    }
   717→  }
   718→}
