     1→/**
     2→ * Handlebars Template Engine for Email Digest Generation
     3→ *
     4→ * Provides sophisticated template compilation, caching, and custom helpers
     5→ * for generating HTML email digests with category grouping and email formatting.
     6→ *
     7→ * Key Features:
     8→ * - Template compilation with automatic caching
     9→ * - Custom Handlebars helpers for date formatting, text manipulation, email parsing
    10→ * - Partial template support for reusable components
    11→ * - File system template loading with caching
    12→ * - Comprehensive error handling with detailed context
    13→ * - Performance optimization through template pre-compilation
    14→ *
    15→ * @packageDocumentation
    16→ */
    17→
    18→import * as Handlebars from 'handlebars';
    19→import * as fs from 'fs/promises';
    20→import * as path from 'path';
    21→
    22→/**
    23→ * Configuration options for TemplateEngine
    24→ */
    25→export interface TemplateEngineOptions {
    26→  /**
    27→   * Directory containing template files
    28→   */
    29→  templateDir: string;
    30→
    31→  /**
    32→   * Maximum number of compiled templates to cache
    33→   * @default 100
    34→   */
    35→  cacheSize?: number;
    36→
    37→  /**
    38→   * Whether to throw errors for missing variables in strict mode
    39→   * @default false
    40→   */
    41→  strict?: boolean;
    42→
    43→  /**
    44→   * Disable HTML escaping (use only for trusted content)
    45→   * @default false
    46→   */
    47→  noEscape?: boolean;
    48→}
    49→
    50→/**
    51→ * Cache statistics for performance monitoring
    52→ */
    53→export interface CacheStats {
    54→  /**
    55→   * Current number of cached templates
    56→   */
    57→  size: number;
    58→
    59→  /**
    60→   * Number of cache hits
    61→   */
    62→  hits: number;
    63→
    64→  /**
    65→   * Number of cache misses
    66→   */
    67→  misses: number;
    68→}
    69→
    70→/**
    71→ * Handlebars Template Engine with caching and custom helpers
    72→ *
    73→ * @example
    74→ * ```typescript
    75→ * const engine = new TemplateEngine({ templateDir: './templates' });
    76→ *
    77→ * // Compile inline template
    78→ * const html = engine.compile('Hello, {{name}}!', { name: 'World' });
    79→ *
    80→ * // Render from file
    81→ * const digest = await engine.renderFromFile('digest.hbs', { emails: [...] });
    82→ *
    83→ * // Register partial
    84→ * engine.registerPartial('email-summary', '<div>{{subject}}</div>');
    85→ * ```
    86→ */
    87→export class TemplateEngine {
    88→  private readonly templateDir: string;
    89→  private readonly cacheSize: number;
    90→  private readonly strict: boolean;
    91→  private readonly noEscape: boolean;
    92→
    93→  /**
    94→   * Cache for compiled Handlebars templates
    95→   * Key: template string or file path
    96→   * Value: compiled template function
    97→   */
    98→  private readonly templateCache: Map<string, HandlebarsTemplateDelegate<unknown>>;
    99→
   100→  /**
   101→   * Cache statistics
   102→   */
   103→  private cacheHits = 0;
   104→  private cacheMisses = 0;
   105→
   106→  /**
   107→   * Create a new TemplateEngine instance
   108→   *
   109→   * @param options - Configuration options
   110→   */
   111→  constructor(options: TemplateEngineOptions) {
   112→    this.templateDir = options.templateDir;
   113→    this.cacheSize = options.cacheSize ?? 100;
   114→    this.strict = options.strict ?? false;
   115→    this.noEscape = options.noEscape ?? false;
   116→
   117→    this.templateCache = new Map();
   118→
   119→    // Register custom helpers on initialization
   120→    this.registerDefaultHelpers();
   121→  }
   122→
   123→  /**
   124→   * Compile and render an inline template string
   125→   *
   126→   * @param templateString - Handlebars template string
   127→   * @param data - Template data context
   128→   * @returns Rendered HTML string
   129→   * @throws Error if template syntax is invalid
   130→   *
   131→   * @example
   132→   * ```typescript
   133→   * const html = engine.compile('Hello, {{name}}!', { name: 'World' });
   134→   * // => "Hello, World!"
   135→   * ```
   136→   */
   137→  public compile(templateString: string, data: Record<string, unknown>): string {
   138→    try {
   139→      // Check cache first
   140→      let template = this.templateCache.get(templateString);
   141→
   142→      if (template) {
   143→        this.cacheHits++;
   144→      } else {
   145→        this.cacheMisses++;
   146→
   147→        // Compile template
   148→        template = Handlebars.compile(templateString, {
   149→          strict: this.strict,
   150→          noEscape: this.noEscape,
   151→        });
   152→
   153→        // Cache with size limit (FIFO eviction)
   154→        if (this.templateCache.size >= this.cacheSize) {
   155→          const firstKey = this.templateCache.keys().next().value;
   156→          if (firstKey !== undefined) {
   157→            this.templateCache.delete(firstKey);
   158→          }
   159→        }
   160→
   161→        this.templateCache.set(templateString, template);
   162→      }
   163→
   164→      // Render template with data
   165→      return template(data);
   166→    } catch (error) {
   167→      if (error instanceof Error) {
   168→        throw new Error(`Template compilation error: ${error.message}`);
   169→      }
   170→      throw error;
   171→    }
   172→  }
   173→
   174→  /**
   175→   * Load and render a template from the file system
   176→   *
   177→   * @param templateName - Template file name (e.g., 'digest.hbs')
   178→   * @param data - Template data context
   179→   * @returns Rendered HTML string
   180→   * @throws Error if template file not found or syntax invalid
   181→   *
   182→   * @example
   183→   * ```typescript
   184→   * const html = await engine.renderFromFile('digest.hbs', {
   185→   *   categories: [...],
   186→   *   totalEmails: 42
   187→   * });
   188→   * ```
   189→   */
   190→  public async renderFromFile(templateName: string, data: Record<string, unknown>): Promise<string> {
   191→    const templatePath = path.join(this.templateDir, templateName);
   192→
   193→    try {
   194→      // Check cache first
   195→      let template = this.templateCache.get(templatePath);
   196→
   197→      if (template) {
   198→        this.cacheHits++;
   199→      } else {
   200→        this.cacheMisses++;
   201→
   202→        // Load template from file
   203→        const templateContent = await fs.readFile(templatePath, 'utf-8');
   204→
   205→        // Compile template
   206→        template = Handlebars.compile(templateContent, {
   207→          strict: this.strict,
   208→          noEscape: this.noEscape,
   209→        });
   210→
   211→        // Cache compiled template
   212→        if (this.templateCache.size >= this.cacheSize) {
   213→          const firstKey = this.templateCache.keys().next().value;
   214→          if (firstKey !== undefined) {
   215→            this.templateCache.delete(firstKey);
   216→          }
   217→        }
   218→
   219→        this.templateCache.set(templatePath, template);
   220→      }
   221→
   222→      // Render template with data
   223→      return template(data);
   224→    } catch (error: unknown) {
   225→      if (error && typeof error === 'object' && 'code' in error && error.code === 'ENOENT') {
   226→        const errno = 'errno' in error ? error.errno : 'unknown';
   227→        throw new Error(`Template file not found: ${templatePath} (errno: ${errno})`);
   228→      }
   229→      if (error instanceof Error) {
   230→        throw new Error(`Template rendering error: ${error.message}`);
   231→      }
   232→      throw error;
   233→    }
   234→  }
   235→
   236→  /**
   237→   * Register a Handlebars partial template
   238→   *
   239→   * @param name - Partial name (used as {{> name}})
   240→   * @param template - Partial template string
   241→   *
   242→   * @example
   243→   * ```typescript
   244→   * engine.registerPartial('email-summary', '<div>{{subject}} - {{from}}</div>');
   245→   *
   246→   * // Use in template
   247→   * const html = engine.compile('{{> email-summary}}', {
   248→   *   subject: 'Hello',
   249→   *   from: 'john@example.com'
   250→   * });
   251→   * ```
   252→   */
   253→  public registerPartial(name: string, template: string): void {
   254→    Handlebars.registerPartial(name, template);
   255→  }
   256→
   257→  /**
   258→   * Unregister a Handlebars partial template
   259→   *
   260→   * @param name - Partial name to unregister
   261→   */
   262→  public unregisterPartial(name: string): void {
   263→    Handlebars.unregisterPartial(name);
   264→  }
   265→
   266→  /**
   267→   * Load and register all partial templates from a directory
   268→   *
   269→   * @param partialsDir - Directory containing partial template files
   270→   * @throws Error if directory cannot be read
   271→   *
   272→   * @example
   273→   * ```typescript
   274→   * await engine.loadPartials('./templates/partials');
   275→   * // Loads all *.hbs files as partials with file name as partial name
   276→   * ```
   277→   */
   278→  public async loadPartials(partialsDir: string): Promise<void> {
   279→    try {
   280→      const files = await fs.readdir(partialsDir);
   281→
   282→      for (const file of files) {
   283→        if (file.endsWith('.hbs') || file.endsWith('.handlebars')) {
   284→          const filePath = path.join(partialsDir, file);
   285→          const content = await fs.readFile(filePath, 'utf-8');
   286→          const partialName = path.basename(file, path.extname(file));
   287→
   288→          this.registerPartial(partialName, content);
   289→        }
   290→      }
   291→    } catch (error: unknown) {
   292→      if (error && typeof error === 'object' && 'code' in error && error.code === 'ENOENT') {
   293→        const errno = 'errno' in error ? error.errno : 'unknown';
   294→        throw new Error(`Partials directory not found: ${partialsDir} (errno: ${errno})`);
   295→      }
   296→      throw error;
   297→    }
   298→  }
   299→
   300→  /**
   301→   * Register a custom Handlebars helper function
   302→   *
   303→   * @param name - Helper name
   304→   * @param helperFn - Helper function
   305→   *
   306→   * @example
   307→   * ```typescript
   308→   * engine.registerHelper('shout', (text: string) => text.toUpperCase());
   309→   *
   310→   * const html = engine.compile('{{shout message}}', { message: 'hello' });
   311→   * // => "HELLO"
   312→   * ```
   313→   */
   314→  public registerHelper(name: string, helperFn: Handlebars.HelperDelegate): void {
   315→    Handlebars.registerHelper(name, helperFn);
   316→  }
   317→
   318→  /**
   319→   * Pre-compile multiple templates for better performance
   320→   *
   321→   * @param templates - Map of template name to template string
   322→   *
   323→   * @example
   324→   * ```typescript
   325→   * await engine.precompileTemplates({
   326→   *   greeting: 'Hello, {{name}}!',
   327→   *   farewell: 'Goodbye, {{name}}!'
   328→   * });
   329→   * ```
   330→   */
   331→  public async precompileTemplates(templates: Record<string, string>): Promise<void> {
   332→    for (const [, templateString] of Object.entries(templates)) {
   333→      const template = Handlebars.compile(templateString, {
   334→        strict: this.strict,
   335→        noEscape: this.noEscape,
   336→      });
   337→
   338→      this.templateCache.set(templateString, template);
   339→    }
   340→  }
   341→
   342→  /**
   343→   * Clear all cached templates
   344→   */
   345→  public clearCache(): void {
   346→    this.templateCache.clear();
   347→    this.cacheHits = 0;
   348→    this.cacheMisses = 0;
