import { DigestGenerator } from '../../src/digest/real-digest-generator';
import { TemplateEngine } from '../../src/digest/template-engine';
import { PrismaClient } from '@prisma/client';
import type { EmailDigest } from '../../src/types/email-digest';

// Mock dependencies
jest.mock('../../src/digest/template-engine');
jest.mock('@prisma/client');

describe('DigestGenerator (T046) - Fixed Mocks', () => {
  let digestGenerator: DigestGenerator;
  let mockPrisma: jest.Mocked<PrismaClient>;
  let mockTemplateEngine: jest.Mocked<TemplateEngine>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create mock Prisma client
    mockPrisma = {
      category: {
        findMany: jest.fn(),
      },
      gmailMessage: {
        findMany: jest.fn(),
      },
      sessionCategory: {
        findMany: jest.fn(),
      },
      detectedAttribute: {
        findMany: jest.fn(),
      },
    } as unknown as jest.Mocked<PrismaClient>;

    // Create mock TemplateEngine
    mockTemplateEngine = {
      compile: jest.fn(),
      registerPartial: jest.fn(),
    } as unknown as jest.Mocked<TemplateEngine>;

    // Initialize DigestGenerator with mocks
    digestGenerator = new DigestGenerator(mockPrisma, mockTemplateEngine);
  });

  describe('Category Grouping Logic', () => {
    it('should group emails by primary category', async () => {
      // Setup: Mock database response with multiple emails in different categories
      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([
        {
          gmailId: 'msg-001',
          subject: 'Invoice from Acme Corp',
          fromSimple: [{ email: 'billing@acme.com' }],
          sentAt: new Date('2025-10-10T10:00:00Z'),
          bodyText: 'Your invoice for October...',
        },
        {
          gmailId: 'msg-002',
          subject: 'Newsletter: Tech Updates',
          fromSimple: [{ email: 'news@tech.com' }],
          sentAt: new Date('2025-10-10T11:00:00Z'),
          bodyText: 'Latest technology news...',
        },
        {
          gmailId: 'msg-003',
          subject: 'Receipt from Amazon',
          fromSimple: [{ email: 'orders@amazon.com' }],
          sentAt: new Date('2025-10-10T12:00:00Z'),
          bodyText: 'Thank you for your order...',
        },
      ]);

      (mockPrisma.sessionCategory.findMany as jest.Mock).mockResolvedValue([
        {
          session: { gmailId: 'msg-001', sessionId: 1n },
          categoryId: 1,
          isPrimary: true,
          confidence: 0.95,
          aiClassified: false,
        },
        {
          session: { gmailId: 'msg-002', sessionId: 2n },
          categoryId: 2,
          isPrimary: true,
          confidence: 0.88,
          aiClassified: false,
        },
        {
          session: { gmailId: 'msg-003', sessionId: 3n },
          categoryId: 1,
          isPrimary: true,
          confidence: 0.92,
          aiClassified: false,
        },
      ]);

      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'financial', displayName: 'Financial', description: 'Financial emails' },
        { categoryId: 2, code: 'newsletters', displayName: 'Newsletters', description: 'Newsletter emails' },
      ]);

      (mockPrisma.detectedAttribute.findMany as jest.Mock).mockResolvedValue([]);

      mockTemplateEngine.loadTemplate.mockReturnValue('<div>{{digestType}}</div>');
      mockTemplateEngine.compile.mockReturnValue('<html>Digest</html>');

      const dateRange = {
        start: new Date('2025-10-10T00:00:00Z'),
        end: new Date('2025-10-10T23:59:59Z'),
      };

      const digest = await digestGenerator.generateDigest({
        digestType: 'daily',
        dateRange,
        recipientEmail: 'user@example.com',
      });

      // Assertions: Should have 2 categories (financial and newsletters)
      expect(digest.categories).toHaveLength(2);

      const financialCategory = digest.categories.find((c) => c.categoryName === 'financial');
      expect(financialCategory).toBeDefined();
      expect(financialCategory?.emailCount).toBe(2); // msg-001 and msg-003

      const newslettersCategory = digest.categories.find((c) => c.categoryName === 'newsletters');
      expect(newslettersCategory).toBeDefined();
      expect(newslettersCategory?.emailCount).toBe(1); // msg-002
    });

    it('should sort categories by priority', async () => {
      (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
        { categoryId: 1, code: 'newsletters', displayName: 'Newsletters', description: null },
        { categoryId: 2, code: 'financial', displayName: 'Financial', description: null },
